import React, { useEffect, useState } from "react";
import socket from "../socket";

function Player() {
  const [name, setName] = useState("");
  const [joined, setJoined] = useState(false);
  const [started, setStarted] = useState(false);
  const [questions, setQuestions] = useState([]);
  const [current, setCurrent] = useState(0);
  const [score, setScore] = useState(0);

  // Load questions
  useEffect(() => {
    fetch("http://localhost:5000/api/game")
      .then((res) => res.json())
      .then((data) => setQuestions(data));
  }, []);

  // Socket listeners
  useEffect(() => {
    console.log("🎧 Listening to socket events");

    socket.on("gameStarted", () => {
      console.log("🔥 GAME STARTED RECEIVED");
      setStarted(true);
    });

    socket.on("nextQuestion", (index) => {
      setCurrent(index);
    });

    socket.on("updateScore", ({ player, total }) => {
      if (player === name) {
        setScore(total);
      }
    });

    return () => {
      socket.off("gameStarted");
      socket.off("nextQuestion");
      socket.off("updateScore");
    };
  }, [name]);

  const joinGame = () => {
    socket.emit("joinGame", name);
    setJoined(true);
  };

  const answer = (opt) => {
    socket.emit("answer", {
      player: name,
      answer: opt,
      correctAnswer: questions[current].answer,
    });
  };

  return (
    <div>
      <h1>Player</h1>

      {!joined ? (
        <>
          <input
            placeholder="Enter name"
            onChange={(e) => setName(e.target.value)}
          />
          <button onClick={joinGame}>Join</button>
        </>
      ) : !started ? (
        <p>Waiting for host...</p>
      ) : (
        <>
          <h2>{questions[current]?.question}</h2>

          {questions[current]?.options.map((opt, i) => (
            <button key={i} onClick={() => answer(opt)}>
              {opt}
            </button>
          ))}

          <h3>Score: {score}</h3>
        </>
      )}
    </div>
  );
}

export default Player;
